			var xpathId = REF_DATA_XPATH + "/Courts/Court[./Code = '" + code + "']/Id";
			var venueName = Services.getValue(xpathName);
			var venueId = Services.getValue(xpathId);
		
			// Set the data in the business part of the model
			if(venueName != null && venueName != ""){
				// set the description field appropriately
				Services.setValue(SelectVenue_VenueName2.dataBinding, venueName);		
				Services.setValue(CourtsLOVGrid2.dataBinding, venueId);		
			}
			else{
				// Clear the fields
				Services.setValue(SelectVenue_VenueName2.dataBinding, "");
			}
		} // end of logic()
		
