		/****************************************************************************************************************/
		function SelectVenue_OKBtn2() {}
		SelectVenue_OKBtn2.actionBinding = function()
		{
			// set the details on the add hearing popup
			// First retrieve values from the tmp area of the DOM
			var venueCode = Services.getValue(SelectVenue_VenueCode2.dataBinding);
			var venueName = Services.getValue(SelectVenue_VenueName2.dataBinding);
			var addressId = Services.getValue(selectVenue_Address_Grid2.dataBinding);
			var add1 = Services.getValue(SelectVenue_ContactDetails_Address_Line1_2.dataBinding);
			var add2 = Services.getValue(SelectVenue_ContactDetails_Address_Line2_2.dataBinding);	
			var add3 = Services.getValue(SelectVenue_ContactDetails_Address_Line3_2.dataBinding);	
			var add4 = Services.getValue(SelectVenue_ContactDetails_Address_Line4_2.dataBinding);
			var add5 = Services.getValue(SelectVenue_ContactDetails_Address_Line5_2.dataBinding);
			var postcode = Services.getValue(SelectVenue_ContactDetails_Address_Postcode2.dataBinding);		
			var dxNo = Services.getValue(SelectVenue_ContactDetails_Address_DXNumber2.dataBinding);
			var telNo = Services.getValue(SelectVenue_ContactDetails_Address_TelephoneNumber2.dataBinding);
			var faxNo = Services.getValue(SelectVenue_ContactDetails_Address_FaxNumber2.dataBinding);
			
			// Need to ensure all mandatory data is entered and all data is valid
			// If a venue has been selected the address fields are populated automatically.
			// Just need to ensure that the first address line has detail in and 
			// therefore no need to validate the other address field   s.
			var screenValid = true;
			if((venueCode == null || venueCode == "") || (venueName == null || venueName == "") || (add1 == null || add2 == "")){
				screenValid = false;	
			}
			
			if(screenValid){
			  	//if (confirm("feel like debugging?")) debugger;
			    //something buggy? going on with autocomplete gui: returns a code instead of name
			    
			    //check venue name is a code
		     	var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code = '" + venueName + "']/Name";	 
			 	var checkVenueName = Services.getValue(xpathName);
			 	if( null != checkVenueName && checkVenueName.length > 0)   
		    	{  //value of checkVenueName is actually a code
		    		//replace code with venuename
		    		venueName = checkVenueName;
		    	}
			
				FormController.getInstance().hideFormExtensionPopup("SelectVenue");
				// Set the data in the business part of the model
				Services.setValue(Hearing2Courtname.dataBinding, venueName);
				Services.setValue(NEW_HEARING_TMP_PATH2 + "/Address/AddressId", addressId);
				Services.setValue(Hearing2VenueAddressLine1.dataBinding, add1);
				Services.setValue(Hearing2VenueAddressLine2.dataBinding, add2);			
				Services.setValue(Hearing2VenueAddressLine3.dataBinding, add3);
				Services.setValue(Hearing2VenueAddressLine4.dataBinding, add4);
				Services.setValue(Hearing2VenueAddressLine5.dataBinding, add5);
				Services.setValue(Hearing2VenuePostcode.dataBinding, postcode);	
				
				// Clear out the temp data
				//resetVenuePopup();	
			}
			else{
				//alert("Please ensure you have entered Venue Details.");
			}// end of if/else(screenValid){
			//Services.setFocus("VenueLOVBtn"); leave this line out until hearing attendees has an adaptor
		}
		
